mapper.select:
SELECT
ecct.*,
te.actual_name as employeeName,
d.name departmentName
FROM t_shipper_track ecct
LEFT JOIN t_employee te on ecct.employee_id = te.employee_id
left join t_department d on d.department_id = te.department_id

    ecct.shipper_id = #{query.shipperId}

        AND ecct.employee_id = #{query.employeeId}


        AND INSTR(ecct.track_content,#{query.keywords})


        and DATE_FORMAT(ecct.create_time,'%Y-%m-%d') >= #{query.startTime}


        and DATE_FORMAT(ecct.create_time,'%Y-%m-%d') <= #{query.endTime}



    ORDER BY ecct.create_time DESC

select * from t_shipper_track where shipper_id in

    #{item}

order by create_time desc
